CREATE TABLE IF NOT EXISTS species_profiles (
  canonical_name TEXT PRIMARY KEY,
  category TEXT NOT NULL CHECK (category IN ('fish', 'crustacean', 'shellfish', 'salmon', 'other')),
  korean_name TEXT NOT NULL,
  scientific_name TEXT,
  english_name TEXT,
  aliases TEXT NOT NULL DEFAULT '',
  season_months TEXT NOT NULL,
  season_note TEXT NOT NULL,
  market_weight_note TEXT NOT NULL,
  habitat_note TEXT NOT NULL,
  taste_note TEXT NOT NULL,
  buying_note TEXT NOT NULL,
  photo_url TEXT NOT NULL,
  photo_source_url TEXT NOT NULL,
  photo_attribution TEXT NOT NULL,
  photo_license TEXT NOT NULL,
  info_sources TEXT NOT NULL,
  sort_order INTEGER NOT NULL DEFAULT 999,
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_species_profiles_category_sort
ON species_profiles(category, sort_order, canonical_name);

INSERT INTO species_profiles (
  canonical_name,
  category,
  korean_name,
  scientific_name,
  english_name,
  aliases,
  season_months,
  season_note,
  market_weight_note,
  habitat_note,
  taste_note,
  buying_note,
  photo_url,
  photo_source_url,
  photo_attribution,
  photo_license,
  info_sources,
  sort_order
) VALUES
('광어', 'fish', '광어', 'Paralichthys olivaceus', 'Olive flounder', '넙치', '11~3월', '양식은 연중 안정적이지만 자연산은 겨울부터 초봄까지 살이 단단한 편입니다. 황금광어는 별도 어종이 아니라 광어 변이/상품명으로 함께 봅니다.', '현재 시세 데이터에서는 1~7kg까지 들어오며, 거래 판단은 2~3kg급과 3kg 이상급을 나눠 보는 것이 좋습니다.', '모래나 펄 바닥에 붙어 사는 저서성 어류로 한국, 일본, 중국 연안에 넓게 분포합니다.', '담백하고 식감이 단단해 기본 횟감 기준점으로 쓰기 좋습니다.', '두께가 필요한 날은 2kg 이상, 가격 민감한 날은 1~2kg급과 이벤트 표기를 같이 비교합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Paralichthys-olivaceus-Federal-Way-3583.jpg', 'https://commons.wikimedia.org/wiki/File:Paralichthys-olivaceus-Federal-Way-3583.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://www.busan.go.kr/fisheries/frfishpoint05","https://en.wikipedia.org/wiki/Olive_flounder","https://commons.wikimedia.org/wiki/Paralichthys_olivaceus"]', 10),
('참돔', 'fish', '참돔', 'Pagrus major', 'Red seabream', '도미', '12~5월', '겨울과 봄에 선호도가 높고 봄철 참돔은 도미류 대표 횟감으로 봅니다.', '현재 시세 데이터에서는 2~4.5kg급이 중심입니다.', '연안 암초와 모래가 섞인 바닥을 오가며 한국 남해와 일본 주변에서 많이 다룹니다.', '붉은 껍질과 고소한 단맛이 강점이며 숙성에도 잘 맞습니다.', '도미로 들어온 항목은 참돔 계열인지, 자연산/양식과 원산지 표기를 같이 확인합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Pagrus%20major%20Red%20seabream%20ja01.jpg', 'https://commons.wikimedia.org/wiki/File:Pagrus_major_Red_seabream_ja01.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Pagrus_major","https://commons.wikimedia.org/wiki/Category:Pagrus_major","https://slds2.tistory.com/2287"]', 20),
('감성돔', 'fish', '감성돔', 'Acanthopagrus schlegelii', 'Blackhead seabream', '감생이', '10~3월', '가을부터 겨울까지 지방이 오르는 편이고 겨울 횟감으로 자주 분류됩니다.', '현재 시세 데이터에서는 1~2kg급이 중심입니다.', '연안 암반, 방파제, 하구 주변을 오가며 염분 변화에 강한 돔류입니다.', '단단하고 은은한 단맛이 있어 얇게 떠도 힘이 있습니다.', '작은 개체는 수율이 낮을 수 있어 kg 가격과 마리 크기를 함께 봅니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Acanthopagrus%20schlegelii.JPG', 'https://commons.wikimedia.org/wiki/File:Acanthopagrus_schlegelii.JPG', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Acanthopagrus_schlegelii","https://commons.wikimedia.org/wiki/Category:Acanthopagrus_schlegelii","https://slds2.tistory.com/2287"]', 30),
('돌도다리', 'fish', '돌도다리', 'Kareius bicoloratus', 'Stone flounder', '', '3~5월', '봄 도다리류로 묶어 보는 일이 많지만 실제 상품명은 지역과 판매처에 따라 갈립니다.', '현재 시세 데이터에서는 0.6~2kg급이 들어옵니다.', '모래와 펄 바닥에 붙어 사는 가자미류입니다.', '담백하고 부드러워 봄철 탕과 회 모두에 쓰입니다.', '도다리류는 표준명 혼용이 많으므로 판매처 원문과 크기 표기를 같이 확인합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Kareius%20bicoloratus%20Camouflage.JPG', 'https://commons.wikimedia.org/wiki/File:Kareius_bicoloratus_Camouflage.JPG', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Stone_flounder","https://commons.wikimedia.org/wiki/Category:Kareius_bicoloratus","https://slds2.tistory.com/2287"]', 40),
('능성어', 'fish', '능성어', 'Hyporthodus septemfasciatus', 'Seven-band grouper', '구문쟁이', '12~3월', '겨울 고급 횟감으로 분류되며 큰 개체일수록 숙성 가치가 커집니다.', '현재 시세 데이터에서는 1.3~4kg급이 중심입니다.', '암초와 깊은 연안 바닥에 머무는 바리류입니다.', '살결이 치밀하고 감칠맛이 강해 고급 모둠 구성에 적합합니다.', '바리류는 이름 혼용이 잦아 능성어, 자바리, 붉바리 표기를 분리해 봅니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Epinephelus%20septemfasciatus%20Enosui1.jpg', 'https://commons.wikimedia.org/wiki/File:Epinephelus_septemfasciatus_Enosui1.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Hyporthodus_septemfasciatus","https://commons.wikimedia.org/wiki/Category:Epinephelus_septemfasciatus","https://slds2.tistory.com/2287"]', 50),
('농어', 'fish', '농어', 'Lateolabrax japonicus', 'Japanese sea bass', '', '6~8월', '여름 대표 흰살 횟감으로 분류됩니다.', '현재 시세 데이터에서는 1~4kg급이 들어옵니다.', '연안과 하구 주변을 오가는 회유성 어류입니다.', '여름에는 지방과 탄력이 올라 회와 구이에 모두 잘 맞습니다.', '작은 개체와 큰 개체의 식감 차이가 크므로 중량대별 가격을 나눠 봅니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/%E3%82%B9%E3%82%BA%E3%82%AD.jpg', 'https://commons.wikimedia.org/wiki/File:%E3%82%B9%E3%82%BA%E3%82%AD.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Japanese_sea_bass","https://commons.wikimedia.org/wiki/Category:Lateolabrax_japonicus","https://slds2.tistory.com/2287"]', 60),
('자바리', 'fish', '자바리', 'Epinephelus bruneus', 'Longtooth grouper', '다금바리', '6~8월', '여름 고급 바리류로 많이 찾지만, 산지와 표기 혼동이 특히 많습니다.', '현재 시세 데이터에서는 2~3kg급이 중심입니다.', '따뜻한 남해와 제주권 암초 지대에서 귀하게 다루는 바리류입니다.', '탄탄한 식감과 진한 감칠맛이 특징입니다.', '다금바리 표기가 붙으면 실제 자바리인지 별도 어종/상품명인지 확인합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Epinephelus%20bruneus%20tokai.jpg', 'https://commons.wikimedia.org/wiki/File:Epinephelus_bruneus_tokai.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Epinephelus_bruneus","https://commons.wikimedia.org/wiki/Category:Epinephelus_bruneus","https://slds2.tistory.com/2287"]', 70),
('점성어', 'fish', '점성어', 'Sciaenops ocellatus', 'Red drum', '홍민어', '연중', '국내 시장에서는 수입/양식 홍민어 계열 상품명으로 취급되는 경우가 많아 제철보다 입고 상태가 중요합니다.', '현재 시세 데이터에서는 4~6kg급이 중심입니다.', '원산지는 북서대서양 계열이나 양식과 수입 유통으로 시장에 들어옵니다.', '살이 크고 균일해 단가형 횟감으로 쓰기 좋습니다.', '원산지와 해동/활어 상태, 큰 개체 수율을 같이 확인합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Sciaenops%20ocellatus.jpg', 'https://commons.wikimedia.org/wiki/File:Sciaenops_ocellatus.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://www.fws.gov/species/red-drum-sciaenops-ocellatus","https://animaldiversity.org/accounts/Sciaenops_ocellatus/","https://commons.wikimedia.org/wiki/File:Sciaenops_ocellatus.jpg"]', 80),
('시마아지', 'fish', '시마아지', 'Pseudocaranx dentex', 'White trevally', '흑점줄전갱이', '6~8월', '여름 전갱이류 고급 횟감으로 분류됩니다.', '현재 시세 데이터에서는 1.6~3.3kg급이 들어옵니다.', '온난한 바다의 연안과 외해를 오가는 전갱이류입니다.', '기름과 탄력이 같이 살아 있어 숙성 회로도 평가가 좋습니다.', '일본산/국내산, 자연산/양식 표기를 나눠 비교합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Pseudocaranx%20dentex%20211937492.jpg', 'https://commons.wikimedia.org/wiki/File:Pseudocaranx_dentex_211937492.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/White_trevally","https://commons.wikimedia.org/wiki/Category:Pseudocaranx_dentex","https://slds2.tistory.com/2287"]', 90),
('줄돔', 'fish', '줄돔', 'Oplegnathus punctatus', 'Spotted knifejaw', '이시가키다이', '12~3월', '돌돔류와 함께 겨울 횟감으로 보는 경우가 많습니다.', '현재 시세 데이터에서는 0.7~1.8kg급이 중심입니다.', '암초 주변에 붙는 돔류로 치어와 성어 무늬가 뚜렷합니다.', '쫀득한 식감과 진한 향이 있어 소량 고급 구성에 잘 맞습니다.', '작은 중량대가 많아 한 마리 수율과 kg 단가를 함께 봅니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Ishigakidai070926.jpg', 'https://commons.wikimedia.org/wiki/File:Ishigakidai070926.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Oplegnathus_punctatus","https://commons.wikimedia.org/wiki/Category:Oplegnathus_punctatus","https://slds2.tistory.com/2287"]', 100),
('돌돔', 'fish', '돌돔', 'Oplegnathus fasciatus', 'Barred knifejaw', '시마다이', '9~3월', '가을부터 겨울까지 선호도가 높고 겨울 목록에도 자주 포함됩니다.', '현재 시세 데이터에서는 1.5~1.9kg급이 들어옵니다.', '암초 지대에 붙어 조개류와 갑각류를 먹는 돔류입니다.', '씹는 힘이 강하고 고소한 맛이 특징입니다.', '줄돔과 혼동하지 말고 표준명과 무늬, 가격대를 함께 확인합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Shimadai.jpg', 'https://commons.wikimedia.org/wiki/File:Shimadai.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Barred_knifejaw","https://commons.wikimedia.org/wiki/Category:Oplegnathus_fasciatus","https://slds2.tistory.com/2287"]', 110),
('잿방어', 'fish', '잿방어', 'Seriola dumerili', 'Greater amberjack', '간파치', '9~11월', '가을부터 겨울 초입까지 기름이 오르는 방어류로 봅니다.', '현재 시세 데이터에서는 3.3~5.5kg급이 중심입니다.', '온난한 바다를 회유하는 대형 전갱이과 어류입니다.', '방어보다 산뜻하고 탄탄한 식감을 기대하는 구성에 어울립니다.', '방어, 부시리와 이름이 섞이기 쉬우므로 판매처 원문을 확인합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Seriola%20dumerili%20Minorca.jpg', 'https://commons.wikimedia.org/wiki/File:Seriola_dumerili_Minorca.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Greater_amberjack","https://commons.wikimedia.org/wiki/Category:Seriola_dumerili","https://slds2.tistory.com/2287"]', 120),
('부시리', 'fish', '부시리', 'Seriola lalandi', 'Yellowtail amberjack', '히라스', '6~8월', '여름 방어류로 분류되는 경우가 많고, 겨울 방어와 포지션을 나눠 봅니다.', '현재 시세 데이터에서는 3~6.7kg급이 들어옵니다.', '따뜻한 바다를 넓게 회유하는 대형 전갱이과 어류입니다.', '방어보다 담백하고 탄력이 강한 쪽으로 평가됩니다.', '겨울 방어 대체품인지, 여름 부시리로 들어온 것인지 계절과 원문을 같이 봅니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Kingfish.jpg', 'https://commons.wikimedia.org/wiki/File:Kingfish.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Yellowtail_amberjack","https://commons.wikimedia.org/wiki/Category:Seriola_lalandi","https://slds2.tistory.com/2287"]', 130),
('연어', 'salmon', '연어', 'Salmo salar', 'Atlantic salmon', '', '9~11월', '자연산 연어는 가을 이미지가 강하지만 국내 시세판에서는 수입/양식 연어가 연중 들어옵니다.', '현재 시세 데이터에서는 6~8kg급 원어가 중심입니다.', '상업 유통은 대서양연어 양식 물량 비중이 큽니다.', '지방감이 확실하고 색이 선명해 모둠 구성에서 존재감이 큽니다.', '원산지, 냉장/냉동, 필렛/원어 단위를 함께 확인합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Atlantic%20salmon%20fish.jpg', 'https://commons.wikimedia.org/wiki/File:Atlantic_salmon_fish.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Atlantic_salmon","https://commons.wikimedia.org/wiki/Category:Salmo_salar","https://slds2.tistory.com/2287"]', 140),
('개숭어', 'fish', '개숭어', 'Chelon haematocheilus', 'So-iuy mullet', '가숭어, 참숭어, 밀치', '12~5월', '겨울부터 봄까지 숭어류가 자주 제철 목록에 들어갑니다.', '현재 시세 데이터에서는 1~1.5kg급이 들어옵니다.', '연안과 하구를 오가며 양식과 자연산이 모두 시장에 나옵니다.', '겨울에는 지방이 올라 가성비 횟감으로 쓰기 좋습니다.', '숭어, 보리숭어, 개숭어 표기가 혼용되므로 원문명을 확인합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Mullet%202008%20G1.jpg', 'https://commons.wikimedia.org/wiki/File:Mullet_2008_G1.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Chelon_haematocheilus","https://commons.wikimedia.org/wiki/Category:Chelon_haematocheilus","https://slds2.tistory.com/2287"]', 150),
('도다리', 'fish', '도다리', 'Pleuronichthys cornutus', 'Ridged-eye flounder', '문치가자미, 담배쟁이', '3~8월', '봄 도다리와 여름 도다리류가 모두 시장에서 쓰여 표준명 확인이 중요합니다.', '현재 시세 데이터에서는 0.7~2.5kg급이 들어옵니다.', '모래 바닥에 붙어 사는 가자미류입니다.', '담백하고 부드러운 살로 봄철 수요가 강합니다.', '도다리라는 이름은 여러 가자미류에 붙으므로 판매처 원문과 사진을 함께 봅니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Pleuronichthys%20cornutus%20at%20Osaka%20aquarium.jpg', 'https://commons.wikimedia.org/wiki/File:Pleuronichthys_cornutus_at_Osaka_aquarium.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Ridged-eye_flounder","https://commons.wikimedia.org/wiki/File:Pleuronichthys_cornutus_at_Osaka_aquarium.jpg","https://slds2.tistory.com/2287"]', 160),
('도미', 'fish', '도미', 'Pagrus major', 'Sea bream', '', '12~5월', '시장명 도미는 참돔 또는 돔류 총칭으로 들어오는 경우가 많습니다.', '현재 시세 데이터에서는 1.2~3kg급이 들어옵니다.', '돔류는 연안 암초와 모래 바닥 주변에 많습니다.', '참돔 계열이면 단맛과 탄력이 장점입니다.', '정확한 어종이 필요하면 참돔/감성돔/돌돔과 구분되는지 확인합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Pagrus%20major%20Red%20seabream%20ja01.jpg', 'https://commons.wikimedia.org/wiki/File:Pagrus_major_Red_seabream_ja01.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Pagrus_major","https://commons.wikimedia.org/wiki/Category:Pagrus_major","https://slds2.tistory.com/2287"]', 170),
('방어', 'fish', '방어', 'Seriola quinqueradiata', 'Japanese amberjack', '', '11~2월', '겨울 대표 대형 횟감입니다.', '현재 시세 데이터에서는 7~8kg급이 확인됩니다.', '온대 해역을 회유하며 겨울에 지방을 크게 저장합니다.', '기름진 뱃살과 등살 차이가 뚜렷해 부위 구성이 중요합니다.', '대방어는 총중량, 숙성 여부, 부위 배분을 같이 봅니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Seriola%20quinqueradiata%20%28200810%29.jpg', 'https://commons.wikimedia.org/wiki/File:Seriola_quinqueradiata_(200810).jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Japanese_amberjack","https://commons.wikimedia.org/wiki/Category:Seriola_quinqueradiata","https://slds2.tistory.com/2287"]', 180),
('뱅에돔', 'fish', '뱅에돔', 'Girella punctata', 'Largescale blackfish', '벵에돔', '6~9월', '여름부터 가을 초입까지 선호되는 갯바위 돔류입니다.', '현재 시세 데이터에서는 0.6kg급이 확인됩니다.', '암초와 해조류가 있는 연안에 붙어 삽니다.', '향이 있고 살이 단단해 소량 구성에 잘 어울립니다.', '작은 개체는 수율이 낮으므로 총량과 단가를 같이 확인합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Gure.jpg', 'https://commons.wikimedia.org/wiki/File:Gure.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://commons.wikimedia.org/wiki/Category:Girella_punctata","https://slds2.tistory.com/2287"]', 190),
('보리숭어', 'fish', '보리숭어', 'Mugil cephalus', 'Flathead grey mullet', '', '3~5월', '보리 수확철 이름과 연결되어 봄 숭어류로 불립니다.', '현재 시세 데이터에서는 1~1.3kg급이 들어옵니다.', '연안과 하구를 오가며 흔히 잡히는 숭어류입니다.', '담백하고 가격 접근성이 좋아 모둠 보강에 쓰입니다.', '숭어류는 산지와 수질 영향이 커 원산지와 활력 상태를 같이 봅니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Mugil%20cephalus%20Minorca%20%28cropped%29.jpg', 'https://commons.wikimedia.org/wiki/File:Mugil_cephalus_Minorca_(cropped).jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Flathead_grey_mullet","https://commons.wikimedia.org/wiki/Category:Mugil_cephalus","https://slds2.tistory.com/2287"]', 200),
('복어', 'fish', '복어', 'Takifugu spp.', 'Pufferfish', '', '11~3월', '복어류는 겨울철 선호도가 높지만 독성 관리가 핵심입니다.', '현재 시세 데이터에서는 2~3kg급이 확인됩니다.', '복어류는 종마다 분포와 독성 부위가 다릅니다.', '맑은 감칠맛이 강하지만 전문 손질 전제가 필요합니다.', '식용 가능 종과 손질 자격, 원산지를 반드시 확인합니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Takifugu%20rubripes%20by%20OpenCage.jpg', 'https://commons.wikimedia.org/wiki/File:Takifugu_rubripes_by_OpenCage.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Takifugu","https://commons.wikimedia.org/wiki/Category:Takifugu","https://slds2.tistory.com/2287"]', 210),
('붉바리', 'fish', '붉바리', 'Epinephelus akaara', 'Hong Kong grouper', '아까바리', '12~3월', '겨울 고급 바리류로 분류되는 경우가 많습니다.', '현재 시세 데이터에서는 0.5~0.7kg급이 확인됩니다.', '따뜻한 암초 지대에 사는 소형 바리류입니다.', '작아도 감칠맛이 진하고 고급감이 있습니다.', '크기가 작으면 kg 단가가 높아도 실수율을 함께 봅니다.', 'https://commons.wikimedia.org/wiki/Special:FilePath/Epinephelus%20akaara%20Toba.jpg', 'https://commons.wikimedia.org/wiki/File:Epinephelus_akaara_Toba.jpg', 'Wikimedia Commons contributors', 'See source file', '["https://en.wikipedia.org/wiki/Hong_Kong_grouper","https://commons.wikimedia.org/wiki/Category:Epinephelus_akaara","https://slds2.tistory.com/2287"]', 220),
